function sharePost(){navigator.share?navigator.share({title:document.title,url:window.location.href}):alert("Share not supported")}function goToState(e){e!==""&&(window.location.href=e)}document.addEventListener("DOMContentLoaded",function(){let e=window.location.pathname.replace(/\/$/,""),t=document.getElementById("stateSelect");for(let n of t.options){let s=n.value.replace(/\/$/,"");s===e&&(n.selected=!0)}});function goToSearch(){let e=document.getElementById("searchInput").value.trim();window.location.href="/search/?q="+encodeURIComponent(e)}